#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>

#define InitSize 10
typedef int ElemType;

typedef struct {
    ElemType *data;
    int length;
    int maxSize;
} SqList;

bool InitList(SqList *L) {
    L->data = (ElemType *)malloc(sizeof(ElemType) * InitSize);
    if (L->data == NULL) {
        return false;
    }
    L->length = 0;
    L->maxSize = InitSize;
    return true;
}

bool IncreaseSize(SqList *L, int len) {
    ElemType *old = L->data;
    ElemType *newData = (ElemType *)malloc(sizeof(ElemType) * (L->maxSize + len));
    if (newData == NULL) {
        return false;
    }
    for (int i = 0; i < L->length; ++i) {
        newData[i] = old[i];
    }
    L->data = newData;
    L->maxSize += len;
    free(old);
    return true;
}

void DestroyList(SqList *L) {
    free(L->data);
    L->data = NULL;
    L->length = 0;
    L->maxSize = 0;
}
